solution_code:
import numpy as np

def cls_pool(token_embeddings: np.ndarray) -> np.ndarray:
    # Extract CLS token embedding (position 0) for each sequence in batch
    return token_embeddings[:, 0, :]  # (batch, hidden_dim)

def cls_pool_with_projection(
    token_embeddings: np.ndarray,
    W: np.ndarray,
    b: np.ndarray
) -> np.ndarray:
    cls_embeds = cls_pool(token_embeddings)   # (batch, hidden_dim)
    projected = cls_embeds @ W + b            # (batch, output_dim)
    return np.tanh(projected)
